import { PrismaClient } from '@prisma/client';
import NodeCache from 'node-cache';

const prisma = new PrismaClient();

// Cache for permissions with 5-minute TTL
const permissionCache = new NodeCache({ stdTTL: 300 });

interface PermissionData {
  name: string;
  description?: string;
  module: string;
  action: string;
}

interface RoleData {
  name: string;
  description?: string;
}

export class PermissionService {
  /**
   * Create a new role
   */
  async createRole(data: RoleData) {
    try {
      const role = await prisma.role.create({
        data: {
          name: data.name,
          description: data.description,
        },
        include: { permissions: { include: { permission: true } } }
      });

      // Clear cache
      permissionCache.flushAll();

      return role;
    } catch (error: any) {
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: `Role "${data.name}" sudah ada` };
      }
      throw { statusCode: 500, message: 'Gagal membuat role' };
    }
  }

  /**
   * Update a role
   */
  async updateRole(roleId: string, data: Partial<RoleData>) {
    try {
      const role = await prisma.role.update({
        where: { id: roleId },
        data: {
          ...(data.name && { name: data.name }),
          ...(data.description !== undefined && { description: data.description }),
        },
        include: { permissions: { include: { permission: true } } }
      });

      // Clear cache
      permissionCache.flushAll();

      return role;
    } catch (error: any) {
      if (error.code === 'P2025') {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: `Role "${data.name}" sudah ada` };
      }
      throw { statusCode: 500, message: 'Gagal mengupdate role' };
    }
  }

  /**
   * Delete a role
   */
  async deleteRole(roleId: string) {
    try {
      // Check if role is in use
      const usersWithRole = await prisma.user.count({
        where: { role: { in: ['SUPER_ADMIN', 'ADMIN', 'EDITOR', 'MODERATOR'] } }
      });

      if (usersWithRole > 0) {
        throw { statusCode: 400, message: 'Role masih digunakan oleh user' };
      }

      await prisma.role.delete({ where: { id: roleId } });

      // Clear cache
      permissionCache.flushAll();

      return { success: true, message: 'Role berhasil dihapus' };
    } catch (error: any) {
      if (error.code === 'P2025') {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }
      throw error;
    }
  }

  /**
   * Assign permission to role
   */
  async assignPermission(roleId: string, permissionId: string) {
    try {
      // Verify role exists
      const role = await prisma.role.findUnique({ where: { id: roleId } });
      if (!role) {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }

      // Verify permission exists
      const permission = await prisma.permission.findUnique({ where: { id: permissionId } });
      if (!permission) {
        throw { statusCode: 404, message: 'Permission tidak ditemukan' };
      }

      const rolePermission = await prisma.rolePermission.create({
        data: {
          roleId,
          permissionId,
        },
        include: { permission: true }
      });

      // Clear cache
      permissionCache.flushAll();

      return rolePermission;
    } catch (error: any) {
      if (error.code === 'P2002') {
        throw { statusCode: 409, message: 'Permission sudah diberikan ke role ini' };
      }
      throw error;
    }
  }

  /**
   * Remove permission from role
   */
  async removePermission(roleId: string, permissionId: string) {
    try {
      await prisma.rolePermission.deleteMany({
        where: {
          roleId,
          permissionId,
        }
      });

      // Clear cache
      permissionCache.flushAll();

      return { success: true, message: 'Permission berhasil dihapus dari role' };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal menghapus permission' };
    }
  }

  /**
   * Check if user has specific permission
   */
  async checkPermission(userId: string, module: string, action: string): Promise<boolean> {
    try {
      // Get cache key
      const cacheKey = `perm_${userId}_${module}_${action}`;
      const cached = permissionCache.get<boolean>(cacheKey);
      if (cached !== undefined) {
        return cached;
      }

      // Get user with role
      const user = await prisma.user.findUnique({
        where: { id: userId },
        select: { role: true }
      });

      if (!user) {
        return false;
      }

      // Super admin has all permissions
      if (user.role === 'SUPER_ADMIN') {
        permissionCache.set(cacheKey, true);
        return true;
      }

      // Check if permission exists for this module/action
      const permission = await prisma.permission.findUnique({
        where: { module_action: { module, action } }
      });

      if (!permission) {
        permissionCache.set(cacheKey, false);
        return false;
      }

      // For now, admin/editor/moderator roles have all permissions
      // In future, this can be extended to check RolePermission junction table
      const hasPermission = ['ADMIN', 'EDITOR', 'MODERATOR'].includes(user.role);
      permissionCache.set(cacheKey, hasPermission);

      return hasPermission;
    } catch (error) {
      console.error('Error checking permission:', error);
      return false;
    }
  }

  /**
   * Get all permissions for a role
   */
  async getRolePermissions(roleId: string) {
    try {
      const role = await prisma.role.findUnique({
        where: { id: roleId },
        include: {
          permissions: {
            include: { permission: true }
          }
        }
      });

      if (!role) {
        throw { statusCode: 404, message: 'Role tidak ditemukan' };
      }

      return role;
    } catch (error: any) {
      throw error;
    }
  }

  /**
   * Get all roles
   */
  async getAllRoles() {
    try {
      const roles = await prisma.role.findMany({
        include: {
          permissions: {
            include: { permission: true }
          }
        },
        orderBy: { createdAt: 'desc' }
      });

      return roles;
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil roles' };
    }
  }

  /**
   * Get all permissions
   */
  async getAllPermissions() {
    try {
      const permissions = await prisma.permission.findMany({
        orderBy: [{ module: 'asc' }, { action: 'asc' }]
      });

      return permissions;
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil permissions' };
    }
  }

  /**
   * Seed default permissions
   */
  async seedDefaultPermissions() {
    try {
      const defaultPermissions: PermissionData[] = [
        // Content permissions
        { name: 'content.create', description: 'Create content', module: 'CONTENT', action: 'CREATE' },
        { name: 'content.read', description: 'Read content', module: 'CONTENT', action: 'READ' },
        { name: 'content.update', description: 'Update content', module: 'CONTENT', action: 'UPDATE' },
        { name: 'content.delete', description: 'Delete content', module: 'CONTENT', action: 'DELETE' },

        // User permissions
        { name: 'user.create', description: 'Create user', module: 'USER', action: 'CREATE' },
        { name: 'user.read', description: 'Read user', module: 'USER', action: 'READ' },
        { name: 'user.update', description: 'Update user', module: 'USER', action: 'UPDATE' },
        { name: 'user.delete', description: 'Delete user', module: 'USER', action: 'DELETE' },

        // Analytics permissions
        { name: 'analytics.read', description: 'Read analytics', module: 'ANALYTICS', action: 'READ' },
        { name: 'analytics.export', description: 'Export analytics', module: 'ANALYTICS', action: 'EXPORT' },

        // Settings permissions
        { name: 'settings.read', description: 'Read settings', module: 'SETTINGS', action: 'READ' },
        { name: 'settings.update', description: 'Update settings', module: 'SETTINGS', action: 'UPDATE' },

        // Role permissions
        { name: 'role.create', description: 'Create role', module: 'ROLE', action: 'CREATE' },
        { name: 'role.read', description: 'Read role', module: 'ROLE', action: 'READ' },
        { name: 'role.update', description: 'Update role', module: 'ROLE', action: 'UPDATE' },
        { name: 'role.delete', description: 'Delete role', module: 'ROLE', action: 'DELETE' },
      ];

      let createdCount = 0;

      for (const perm of defaultPermissions) {
        const existing = await prisma.permission.findUnique({
          where: { module_action: { module: perm.module, action: perm.action } }
        });

        if (!existing) {
          await prisma.permission.create({ data: perm });
          createdCount++;
        }
      }

      console.log(`Seeded ${createdCount} new permissions`);
      return { success: true, message: `Seeded ${createdCount} permissions` };
    } catch (error: any) {
      console.error('Error seeding permissions:', error);
      throw { statusCode: 500, message: 'Gagal seed permissions' };
    }
  }
}

export const permissionService = new PermissionService();

import { PrismaClient } from '@prisma/client';
import { UAParser } from 'ua-parser-js';

const prisma = new PrismaClient();

interface DateRange {
  startDate?: Date;
  endDate?: Date;
}

interface PageViewData {
  userId?: string;
  path: string;
  referrer?: string;
  userAgent?: string;
}

interface EventData {
  userId?: string;
  eventType: string;
  eventData?: Record<string, any>;
}

interface DeviceInfoData {
  userId?: string;
  deviceType: string;
  os?: string;
  browser?: string;
}

export class AnalyticsService {
  /**
   * Track page view
   */
  async trackPageView(data: PageViewData) {
    try {
      const pageView = await prisma.pageView.create({
        data: {
          userId: data.userId,
          path: data.path,
          referrer: data.referrer,
          userAgent: data.userAgent,
        }
      });

      return pageView;
    } catch (error: any) {
      console.error('Error tracking page view:', error);
      throw { statusCode: 500, message: 'Gagal track page view' };
    }
  }

  /**
   * Track custom event
   */
  async trackEvent(data: EventData) {
    try {
      const event = await prisma.event.create({
        data: {
          userId: data.userId,
          eventType: data.eventType,
          eventData: data.eventData || {},
        }
      });

      return event;
    } catch (error: any) {
      console.error('Error tracking event:', error);
      throw { statusCode: 500, message: 'Gagal track event' };
    }
  }

  /**
   * Track device info
   */
  async trackDeviceInfo(data: DeviceInfoData) {
    try {
      const deviceInfo = await prisma.deviceInfo.create({
        data: {
          userId: data.userId,
          deviceType: data.deviceType,
          os: data.os,
          browser: data.browser,
        }
      });

      return deviceInfo;
    } catch (error: any) {
      console.error('Error tracking device info:', error);
      throw { statusCode: 500, message: 'Gagal track device info' };
    }
  }

  /**
   * Parse user agent and extract device info
   */
  parseUserAgent(userAgent: string) {
    try {
      const parser = new UAParser(userAgent);
      const result = parser.getResult();

      const deviceType = result.device.type || 'DESKTOP';
      const os = result.os.name;
      const browser = result.browser.name;

      return { deviceType, os, browser };
    } catch (error) {
      console.error('Error parsing user agent:', error);
      return { deviceType: 'DESKTOP', os: undefined, browser: undefined };
    }
  }

  /**
   * Get overview statistics
   */
  async getOverviewStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const [totalPageViews, totalEvents, uniqueUsers, totalDevices] = await Promise.all([
        prisma.pageView.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        }),
        prisma.event.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        }),
        prisma.pageView.findMany({
          where: { timestamp: { gte: startDate, lte: endDate } },
          distinct: ['userId'],
          select: { userId: true }
        }),
        prisma.deviceInfo.count({
          where: { timestamp: { gte: startDate, lte: endDate } }
        })
      ]);

      return {
        totalPageViews,
        totalEvents,
        uniqueUsers: uniqueUsers.length,
        totalDevices,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil overview stats' };
    }
  }

  /**
   * Get content performance statistics
   */
  async getContentStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get page views by content path
      const contentViews = await prisma.pageView.groupBy({
        by: ['path'],
        where: {
          timestamp: { gte: startDate, lte: endDate },
          path: { contains: '/content/' }
        },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 20
      });

      return {
        topContent: contentViews.map(cv => ({
          path: cv.path,
          views: cv._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil content stats' };
    }
  }

  /**
   * Get user growth statistics
   */
  async getUserStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get new users in date range
      const newUsers = await prisma.user.count({
        where: { createdAt: { gte: startDate, lte: endDate } }
      });

      // Get active users (those with page views)
      const activeUsers = await prisma.pageView.findMany({
        where: { timestamp: { gte: startDate, lte: endDate } },
        distinct: ['userId'],
        select: { userId: true }
      });

      // Get total users
      const totalUsers = await prisma.user.count();

      return {
        newUsers,
        activeUsers: activeUsers.length,
        totalUsers,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil user stats' };
    }
  }

  /**
   * Get traffic source breakdown
   */
  async getTrafficStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Get referrer breakdown
      const trafficSources = await prisma.pageView.groupBy({
        by: ['referrer'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      return {
        sources: trafficSources.map(ts => ({
          referrer: ts.referrer || 'Direct',
          views: ts._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil traffic stats' };
    }
  }

  /**
   * Get revenue statistics (placeholder for future implementation)
   */
  async getRevenueStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      // Placeholder - can be extended with actual revenue tracking
      return {
        totalRevenue: 0,
        transactions: 0,
        averageOrderValue: 0,
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil revenue stats' };
    }
  }

  /**
   * Get top pages
   */
  async getTopPages(limit: number = 10, dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const topPages = await prisma.pageView.groupBy({
        by: ['path'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: limit
      });

      return {
        pages: topPages.map(tp => ({
          path: tp.path,
          views: tp._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil top pages' };
    }
  }

  /**
   * Get device breakdown statistics
   */
  async getDeviceStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const deviceStats = await prisma.deviceInfo.groupBy({
        by: ['deviceType'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      const osStats = await prisma.deviceInfo.groupBy({
        by: ['os'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 10
      });

      const browserStats = await prisma.deviceInfo.groupBy({
        by: ['browser'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 10
      });

      return {
        devices: deviceStats.map(ds => ({
          type: ds.deviceType,
          count: ds._count.id
        })),
        operatingSystems: osStats.map(os => ({
          name: os.os || 'Unknown',
          count: os._count.id
        })),
        browsers: browserStats.map(bs => ({
          name: bs.browser || 'Unknown',
          count: bs._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil device stats' };
    }
  }

  /**
   * Get traffic sources
   */
  async getTrafficSources(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const sources = await prisma.pageView.groupBy({
        by: ['referrer'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } },
        take: 20
      });

      return {
        sources: sources.map(s => ({
          referrer: s.referrer || 'Direct',
          views: s._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil traffic sources' };
    }
  }

  /**
   * Get event statistics
   */
  async getEventStats(dateRange?: DateRange) {
    try {
      const { startDate, endDate } = this.getDateRange(dateRange);

      const eventStats = await prisma.event.groupBy({
        by: ['eventType'],
        where: { timestamp: { gte: startDate, lte: endDate } },
        _count: { id: true },
        orderBy: { _count: { id: 'desc' } }
      });

      return {
        events: eventStats.map(es => ({
          type: es.eventType,
          count: es._count.id
        })),
        dateRange: { startDate, endDate }
      };
    } catch (error: any) {
      throw { statusCode: 500, message: 'Gagal mengambil event stats' };
    }
  }

  /**
   * Helper: Get date range (default to last 30 days)
   */
  private getDateRange(dateRange?: DateRange) {
    const endDate = dateRange?.endDate || new Date();
    const startDate = dateRange?.startDate || new Date(endDate.getTime() - 30 * 24 * 60 * 60 * 1000);

    return { startDate, endDate };
  }

  /**
   * Clean up old analytics data (older than 90 days)
   */
  async cleanupOldData() {
    try {
      const ninetyDaysAgo = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000);

      const [deletedPageViews, deletedEvents, deletedDevices] = await Promise.all([
        prisma.pageView.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        }),
        prisma.event.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        }),
        prisma.deviceInfo.deleteMany({
          where: { timestamp: { lt: ninetyDaysAgo } }
        })
      ]);

      console.log(`Cleaned up analytics data: ${deletedPageViews.count} page views, ${deletedEvents.count} events, ${deletedDevices.count} device records`);

      return {
        success: true,
        deleted: {
          pageViews: deletedPageViews.count,
          events: deletedEvents.count,
          devices: deletedDevices.count
        }
      };
    } catch (error: any) {
      console.error('Error cleaning up analytics data:', error);
      throw { statusCode: 500, message: 'Gagal cleanup analytics data' };
    }
  }
}

export const analyticsService = new AnalyticsService();

import { FastifyRequest, FastifyReply } from 'fastify';
import { permissionService } from '../services/permissionService';

/**
 * Middleware: Require specific permission (module + action)
 * Usage: fastify.get('/api/admin/users', { preHandler: [requirePermission('USER', 'READ')] }, handler)
 */
export function requirePermission(module: string, action: string) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const { id: userId } = request.user as { id: string };

      const hasPermission = await permissionService.checkPermission(userId, module, action);

      if (!hasPermission) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Permission ${module}:${action} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require specific role
 * Usage: fastify.get('/api/admin/users', { preHandler: [requireRole('ADMIN')] }, handler)
 */
export function requireRole(role: string) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const userRole = (request.user as { role: string }).role;

      if (userRole !== role) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Role ${role} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require any of multiple roles
 * Usage: fastify.get('/api/admin/users', { preHandler: [requireAnyRole(['ADMIN', 'EDITOR'])] }, handler)
 */
export function requireAnyRole(roles: string[]) {
  return async (request: FastifyRequest, reply: FastifyReply) => {
    try {
      await request.jwtVerify();
      const userRole = (request.user as { role: string }).role;

      if (!roles.includes(userRole)) {
        return reply.status(403).send({
          success: false,
          message: `Akses ditolak. Salah satu role ${roles.join(', ')} diperlukan.`
        });
      }
    } catch (err) {
      return reply.status(401).send({
        success: false,
        message: 'Token tidak valid atau sudah expired'
      });
    }
  };
}

/**
 * Middleware: Require super admin only
 */
export function requireSuperAdminOnly(request: FastifyRequest, reply: FastifyReply) {
  return requireRole('SUPER_ADMIN')(request, reply);
}

import { FastifyRequest, FastifyReply } from 'fastify';
import { analyticsService } from '../services/analyticsService';

/**
 * Middleware: Track page views automatically
 * Non-blocking async tracking
 */
export async function trackPageViewMiddleware(request: FastifyRequest, reply: FastifyReply) {
  try {
    // Extract user ID from JWT if available
    let userId: string | undefined;
    try {
      await request.jwtVerify();
      userId = (request.user as { id: string }).id;
    } catch {
      // User not authenticated, continue without userId
    }

    // Extract device info from user agent
    const userAgent = request.headers['user-agent'] || '';
    const deviceInfo = analyticsService.parseUserAgent(userAgent);

    // Extract referrer
    const referrer = request.headers['referer'] as string | undefined;

    // Track page view asynchronously (non-blocking)
    setImmediate(async () => {
      try {
        await analyticsService.trackPageView({
          userId,
          path: request.url,
          referrer,
          userAgent
        });

        // Track device info if userId is available
        if (userId) {
          await analyticsService.trackDeviceInfo({
            userId,
            deviceType: deviceInfo.deviceType,
            os: deviceInfo.os,
            browser: deviceInfo.browser
          });
        }
      } catch (error) {
        console.error('Error tracking page view:', error);
      }
    });
  } catch (error) {
    console.error('Error in analytics middleware:', error);
  }
}

/**
 * Helper: Track custom event
 * Can be called from route handlers
 */
export async function trackEvent(
  userId: string | undefined,
  eventType: string,
  eventData?: Record<string, any>
) {
  try {
    await analyticsService.trackEvent({
      userId,
      eventType,
      eventData
    });
  } catch (error) {
    console.error('Error tracking event:', error);
  }
}

/**
 * Helper: Track event asynchronously (non-blocking)
 */
export function trackEventAsync(
  userId: string | undefined,
  eventType: string,
  eventData?: Record<string, any>
) {
  setImmediate(() => {
    trackEvent(userId, eventType, eventData).catch(err => {
      console.error('Error in async event tracking:', err);
    });
  });
}

import { FastifyInstance } from 'fastify';
