    '/api/admin/roles/:id',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };

        const result = await permissionService.deleteRole(id);

        return {
          success: true,
          message: result.message
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal menghapus role'
        });
      }
    }
  );

  /**
   * POST /api/admin/roles/:id/permissions
   * Assign permission to role
   */
  fastify.post(
    '/api/admin/roles/:id/permissions',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id } = request.params as { id: string };
        const { permissionId } = request.body as { permissionId: string };

        if (!permissionId) {
          return reply.status(400).send({
            success: false,
            message: 'Permission ID wajib diisi'
          });
        }

        const rolePermission = await permissionService.assignPermission(id, permissionId);

        return {
          success: true,
          message: 'Permission berhasil diberikan ke role',
          data: rolePermission
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal memberikan permission'
        });
      }
    }
  );

  /**
   * DELETE /api/admin/roles/:id/permissions/:permissionId
   * Remove permission from role
   */
  fastify.delete(
    '/api/admin/roles/:id/permissions/:permissionId',
    { preHandler: [requireRole('SUPER_ADMIN')] },
    async (request, reply) => {
      try {
        const { id, permissionId } = request.params as { id: string; permissionId: string };

        const result = await permissionService.removePermission(id, permissionId);

        return {
          success: true,
          message: result.message
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal menghapus permission'
        });
      }
    }
  );

  /**
   * GET /api/admin/permissions
   * List all permissions
   */
  fastify.get(
    '/api/admin/permissions',
    { preHandler: [requireAnyRole(['SUPER_ADMIN', 'ADMIN'])] },
    async (request, reply) => {
      try {
        const permissions = await permissionService.getAllPermissions();

        // Group by module
        const grouped = permissions.reduce((acc: Record<string, any[]>, perm: any) => {
          if (!acc[perm.module]) {
            acc[perm.module] = [];
          }
          acc[perm.module].push(perm);
          return acc;
        }, {});

        return {
          success: true,
          data: {
            all: permissions,
            grouped
          }
        };
      } catch (error: any) {
        const status = error.statusCode || 500;
        return reply.status(status).send({
          success: false,
          message: error.message || 'Gagal mengambil permissions'
        });
      }
    }
