        name: 'Content Manager',
        description: 'Manages content'
      });

      await permissionService.seedDefaultPermissions();
      const permissions = await permissionService.getAllPermissions();
      const contentCreatePerm = permissions.find(
        p => p.module === 'CONTENT' && p.action === 'CREATE'
      );

      if (contentCreatePerm) {
        const rolePermission = await permissionService.assignPermission(
          role.id,
          contentCreatePerm.id
        );

        expect(rolePermission).toBeDefined();
        expect(rolePermission.roleId).toBe(role.id);
        expect(rolePermission.permissionId).toBe(contentCreatePerm.id);
