        name: 'Full Permission Role',
        description: 'Test role'
      });

      await permissionService.seedDefaultPermissions();
      const permissions = await permissionService.getAllPermissions();
      const perm1 = permissions[0];
      const perm2 = permissions[1];

      await permissionService.assignPermission(role.id, perm1.id);
      await permissionService.assignPermission(role.id, perm2.id);

      const roleWithPerms = await permissionService.getRolePermissions(role.id);

      expect(roleWithPerms.permissions.length).toBe(2);
      expect(roleWithPerms.permissions.some(rp => rp.permissionId === perm1.id)).toBe(true);
      expect(roleWithPerms.permissions.some(rp => rp.permissionId === perm2.id)).toBe(true);
    });
  });

  describe('checkPermission', () => {
    it('should return true for SUPER_ADMIN', async () => {
      // Create a super admin user
      const user = await prisma.user.create({
        data: {
          email: 'superadmin@test.com',
          username: 'superadmin',
          password: 'hashed',
          role: 'SUPER_ADMIN'
        }
      });

      const hasPermission = await permissionService.checkPermission(
        user.id,
        'CONTENT',
        'CREATE'
      );

      expect(hasPermission).toBe(true);

      // Cleanup
      await prisma.user.delete({ where: { id: user.id } });
    });

    it('should return true for ADMIN with permission', async () => {
      const user = await prisma.user.create({
        data: {
          email: 'admin@test.com',
          username: 'admin',
          password: 'hashed',
          role: 'ADMIN'
        }
      });

      const hasPermission = await permissionService.checkPermission(
        user.id,
        'CONTENT',
        'CREATE'
      );

      expect(hasPermission).toBe(true);

      // Cleanup
      await prisma.user.delete({ where: { id: user.id } });
    });

    it('should return false for USER role', async () => {
