        'CONTENT',
        'CREATE'
      );

      expect(hasPermission).toBe(false);

      // Cleanup
      await prisma.user.delete({ where: { id: user.id } });
    });
  });
});

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { PrismaClient } from '@prisma/client';
import { analyticsService } from '../services/analyticsService';

const prisma = new PrismaClient();

describe('AnalyticsService', () => {
  let testUserId: string;

  beforeAll(async () => {
    // Create test user
    const user = await prisma.user.create({
      data: {
        email: 'analytics-test@test.com',
        username: 'analytics-test',
        password: 'hashed',
        role: 'USER'
      }
    });
    testUserId = user.id;

    // Clean up old test data
    await prisma.pageView.deleteMany({});
    await prisma.event.deleteMany({});
    await prisma.deviceInfo.deleteMany({});
  });

  afterAll(async () => {
    // Clean up test data
    await prisma.pageView.deleteMany({});
    await prisma.event.deleteMany({});
    await prisma.deviceInfo.deleteMany({});
    await prisma.user.delete({ where: { id: testUserId } });
    await prisma.$disconnect();
  });

  describe('trackPageView', () => {
    it('should track page view', async () => {
      const pageView = await analyticsService.trackPageView({
        userId: testUserId,
        path: '/content/anime/1',
        referrer: 'https://google.com',
        userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64)'
      });

      expect(pageView).toBeDefined();
      expect(pageView.userId).toBe(testUserId);
      expect(pageView.path).toBe('/content/anime/1');
      expect(pageView.referrer).toBe('https://google.com');
    });

    it('should track page view without userId', async () => {
      const pageView = await analyticsService.trackPageView({
        path: '/home',
        referrer: 'https://google.com',
        userAgent: 'Mozilla/5.0'
      });

      expect(pageView).toBeDefined();
      expect(pageView.userId).toBeNull();
      expect(pageView.path).toBe('/home');
    });
  });

  describe('trackEvent', () => {
    it('should track custom event', async () => {
      const event = await analyticsService.trackEvent({
        userId: testUserId,
        eventType: 'WATCH',
        eventData: { contentId: 'content-1', duration: 3600 }
      });

      expect(event).toBeDefined();
      expect(event.userId).toBe(testUserId);
      expect(event.eventType).toBe('WATCH');
      expect(event.eventData).toEqual({ contentId: 'content-1', duration: 3600 });
    });

    it('should track event without userId', async () => {
      const event = await analyticsService.trackEvent({
        eventType: 'SEARCH',
        eventData: { query: 'anime' }
      });

      expect(event).toBeDefined();
      expect(event.userId).toBeNull();
      expect(event.eventType).toBe('SEARCH');
    });
  });

  describe('trackDeviceInfo', () => {
    it('should track device info', async () => {
      const deviceInfo = await analyticsService.trackDeviceInfo({
        userId: testUserId,
        deviceType: 'DESKTOP',
        os: 'Windows',
        browser: 'Chrome'
      });

      expect(deviceInfo).toBeDefined();
      expect(deviceInfo.userId).toBe(testUserId);
      expect(deviceInfo.deviceType).toBe('DESKTOP');
      expect(deviceInfo.os).toBe('Windows');
      expect(deviceInfo.browser).toBe('Chrome');
    });
  });

  describe('parseUserAgent', () => {
    it('should parse desktop user agent', () => {
      const userAgent = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36';
      const result = analyticsService.parseUserAgent(userAgent);

      expect(result).toBeDefined();
      expect(result.deviceType).toBeDefined();
      expect(result.os).toBeDefined();
      expect(result.browser).toBeDefined();
    });

    it('should parse mobile user agent', () => {
      const userAgent = 'Mozilla/5.0 (iPhone; CPU iPhone OS 14_6 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/14.1.1 Mobile/15E148 Safari/604.1';
      const result = analyticsService.parseUserAgent(userAgent);

      expect(result).toBeDefined();
      expect(result.deviceType).toBeDefined();
    });

    it('should handle invalid user agent gracefully', () => {
      const result = analyticsService.parseUserAgent('invalid-user-agent');

      expect(result).toBeDefined();
      expect(result.deviceType).toBe('DESKTOP');
    });
  });

  describe('getOverviewStats', () => {
    it('should return overview statistics', async () => {
      // Create test data
      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/home'
      });

      await analyticsService.trackEvent({
        userId: testUserId,
        eventType: 'CLICK'
      });

      const stats = await analyticsService.getOverviewStats();

      expect(stats).toBeDefined();
      expect(stats.totalPageViews).toBeGreaterThanOrEqual(0);
      expect(stats.totalEvents).toBeGreaterThanOrEqual(0);
      expect(stats.uniqueUsers).toBeGreaterThanOrEqual(0);
      expect(stats.dateRange).toBeDefined();
    });

    it('should filter by date range', async () => {
      const now = new Date();
      const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

      const stats = await analyticsService.getOverviewStats({
        startDate: yesterday,
        endDate: now
      });

      expect(stats).toBeDefined();
      expect(stats.dateRange.startDate).toEqual(yesterday);
      expect(stats.dateRange.endDate).toEqual(now);
    });
  });

  describe('getContentStats', () => {
    it('should return content statistics', async () => {
      // Create test data
      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/content/anime/1'
      });

      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/content/manga/2'
      });

      const stats = await analyticsService.getContentStats();

      expect(stats).toBeDefined();
      expect(stats.topContent).toBeDefined();
      expect(Array.isArray(stats.topContent)).toBe(true);
    });
  });

  describe('getUserStats', () => {
    it('should return user statistics', async () => {
      const stats = await analyticsService.getUserStats();

      expect(stats).toBeDefined();
      expect(stats.newUsers).toBeGreaterThanOrEqual(0);
      expect(stats.activeUsers).toBeGreaterThanOrEqual(0);
      expect(stats.totalUsers).toBeGreaterThanOrEqual(0);
    });
  });

  describe('getTrafficStats', () => {
    it('should return traffic statistics', async () => {
      // Create test data
      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/home',
        referrer: 'https://google.com'
      });

      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/content',
        referrer: 'https://facebook.com'
      });

      const stats = await analyticsService.getTrafficStats();

      expect(stats).toBeDefined();
      expect(stats.sources).toBeDefined();
      expect(Array.isArray(stats.sources)).toBe(true);
    });
  });

  describe('getRevenueStats', () => {
    it('should return revenue statistics', async () => {
      const stats = await analyticsService.getRevenueStats();

      expect(stats).toBeDefined();
      expect(stats.totalRevenue).toBe(0);
      expect(stats.transactions).toBe(0);
      expect(stats.averageOrderValue).toBe(0);
    });
  });

  describe('getTopPages', () => {
    it('should return top pages', async () => {
      // Create test data
      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/page1'
      });

      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/page1'
      });

      await analyticsService.trackPageView({
        userId: testUserId,
        path: '/page2'
      });

      const stats = await analyticsService.getTopPages(10);

      expect(stats).toBeDefined();
      expect(stats.pages).toBeDefined();
      expect(Array.isArray(stats.pages)).toBe(true);
    });

    it('should respect limit parameter', async () => {
      const stats = await analyticsService.getTopPages(5);

      expect(stats.pages.length).toBeLessThanOrEqual(5);
    });
  });

  describe('getDeviceStats', () => {
    it('should return device statistics', async () => {
      // Create test data
      await analyticsService.trackDeviceInfo({
        userId: testUserId,
        deviceType: 'DESKTOP',
        os: 'Windows',
        browser: 'Chrome'
      });

      await analyticsService.trackDeviceInfo({
        userId: testUserId,
        deviceType: 'MOBILE',
        os: 'iOS',
        browser: 'Safari'
      });

      const stats = await analyticsService.getDeviceStats();

      expect(stats).toBeDefined();
      expect(stats.devices).toBeDefined();
      expect(stats.operatingSystems).toBeDefined();
      expect(stats.browsers).toBeDefined();
      expect(Array.isArray(stats.devices)).toBe(true);
    });
  });

  describe('getTrafficSources', () => {
    it('should return traffic sources', async () => {
      const stats = await analyticsService.getTrafficSources();

      expect(stats).toBeDefined();
      expect(stats.sources).toBeDefined();
      expect(Array.isArray(stats.sources)).toBe(true);
    });
  });

  describe('getEventStats', () => {
    it('should return event statistics', async () => {
      // Create test data
      await analyticsService.trackEvent({
        userId: testUserId,
        eventType: 'CLICK'
      });

      await analyticsService.trackEvent({
        userId: testUserId,
        eventType: 'SEARCH'
      });

      const stats = await analyticsService.getEventStats();

      expect(stats).toBeDefined();
      expect(stats.events).toBeDefined();
      expect(Array.isArray(stats.events)).toBe(true);
    });
  });

  describe('cleanupOldData', () => {
    it('should cleanup old analytics data', async () => {
      const result = await analyticsService.cleanupOldData();

      expect(result).toBeDefined();
      expect(result.success).toBe(true);
      expect(result.deleted).toBeDefined();
      expect(result.deleted.pageViews).toBeGreaterThanOrEqual(0);
      expect(result.deleted.events).toBeGreaterThanOrEqual(0);
      expect(result.deleted.devices).toBeGreaterThanOrEqual(0);
    });
  });
});

